import { useRef, useState } from 'preact/hooks';
import { nukeClass, addClass } from '/utils';

export function SnackBar() {
    const alert = useRef(null);
    
    const [message, setMessage] = useState('');


   

    const close = () => {
        if (alert.current) {
            nukeClass(alert.current, 'opacity-75');
            addClass(alert.current, 'opacity-0');
            setTimeout(() => {
                ['block', 'visible' ].forEach(x => nukeClass(alert.current, x));
                ['hidden', 'invisible'].forEach(x => addClass(alert.current, x));
                setMessage('');
            }, 500);
            
            
        }
    }

    this.show = (msg, time=2000) => {
        setMessage(msg);
        if(alert.current) {
            ['hidden', 'invisible', 'opacity-0'].forEach(x => nukeClass(alert.current, x));
            ['block', 'visible'].forEach(x => addClass(alert.current, x));
            addClass(alert.current, 'opacity-75')
            setTimeout(close, time);     
        } else {
            console.log("alert was null");
        }
    };


    return (
        <div class="fixed z-50 bottom-4 hidden invisible w-full flex transition-all duration-1000 ease-in-out" ref={alert}>
            <div class="flex-1 flex alert shadow-lg bg-black mx-4 rounded-xl w-full text-white">
                <div class="flex-1 text-center">
                {message}
                </div>
            </div>
        </div>
    );
}