import { useState, useRef } from 'preact/hooks';
import { bookData } from '/bookData';
import { configs } from '/configs';
import { searchIndex } from '/searchData'
import { HeaderMenu } from '/pageheader'
import { route } from 'preact-router';

import Fuse from 'fuse.js'


const bookCodeMap = {};
bookData.forEach((x) => bookCodeMap[x.code] = x.name);


function SearchResultsDisplay(props) {
    const goToResults = (address) => {
        //setNavTarget(address);
        props.navManager.navFromRef(address);
    };


    const convertRefCode = (x) => {
        const parts = x.split(' ');
        const code = parts[0];
        return `${bookCodeMap[code]} ${parts.slice(1).join(' ')}`;
    };

    return (
        props.results.map(res => {
            return (
            <div key={res.item.ref} class="mx-4">
                <div class="flex flex-row w-full" key={res.item.ref}>
                    <a class="basis-1/4 w-24 whitespace-pre-line link link-hover mr-2 text-primary"
                    onclick={() => goToResults(res.item.ref)}>{convertRefCode(res.item.ref)}</a>
                    <div class="basis-3/4 w-full whitespace-pre-line text-left">
                        {res.item.text}
                    </div>
                </div>
                <div class="divider m-2" />
            </div>
            );
        })
    );

}

function SearchHeader(props) {
    const searchBar = useRef(null);
    const [value, setValue] = useState('');
    
    
    const searchFuse = new Fuse(searchIndex, {
        keys: ['text']
    }); 


	const doSearch = () => {
		const searchBar = document.getElementById('search-div');

		if (searchBar) {
			searchBar.classList.remove('search-shown');
			searchBar.classList.add('search-hidden');
		}
		if (value) {
			const res = searchFuse.search(value);
            props.setSearchResults(res);
		}
		
	}

    const onInput = (e) => {
        setValue(e.target.value);
    }

    const handleKeyPress = (e) => {
        if (e.key === 'Enter'){
            doSearch();
        }
    }


    const navHome = () => {
        route('/');
    };

    return (
    
    <div class="navbar bg-primary grid grid-cols-5 grid-rows-2" ref={toolbar}>		
        <div class="col-start-1 row-start-1">
            <img src="icons/icon-36.png" id="nav-app-icon" style="min-height:36px; min-width:36px;" />
        </div>
        <span class="btn btn-ghost col-start-3 row-start-1 text-lg text-base-100 link link-hover"
              onclick={navHome}>{configs.home}</span>
        <div class="col-start-5 row-start-1 min-h-36 min-w-36">
            <HeaderMenu  
                class="col-start-5 row-start-1 min-h-36 min-w-36"
                searchBar={searchBar} />
        </div>
        <div class="form-control col-start-2 col-span-2 row-start-2 mt-2 w-full max-w-xs">
            <div class="input-group">
            <input type="text" 
                id="search-box" 
                class="bg-base-100 rounded-r-none border-r-base-100 pl-2 placeholder:italic"
                value={value}
                onInput={onInput}
                onKeyUp={handleKeyPress}
                placeholder={configs.search} />
            <button class="btn btn-square bg-base-100 rounded-l-none border-l-base-100"
                    onclick={doSearch}>{configs.search}</button>
                    </div>
        </div>
    </div>
    );
}

export function SearchPage(props) {
    const [searchResults, setSearchResults] = useState([]);

    return (
        <div class="container mx-auto">
            <header class="sticky top-0 z-50">
                <SearchHeader setSearchResults={setSearchResults} />
            </header>
            <main class="pt-4">
                <SearchResultsDisplay 
                    results={searchResults} 
                    navManager={props.navManager} />
            </main>
        </div>
    );
}