import { h } from 'preact';
import { useRef,  useEffect } from 'preact/hooks';
import { configs } from '/configs';
import { nukeClass, addClass } from '/utils';





export function PageFooter(props) {
		
	const audioElem = useRef(null);
	const audioI = useRef(null);
	const playButton = useRef(null);
	const nextButton = useRef(null);
	const prevButton = useRef(null);
	const fnRef = useRef(null);


	useEffect(() => {
		props.audioManager.injectAudioElems(audioElem, audioI, playButton);
	// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [])
	
	
	const setupButton = (btn, path) => {
		if (btn.current){
			if (path === ''){
				btn.current.style.visibility = 'hidden';				
			} else {
				btn.current.style.visibility = 'visible';
			}		
		}
	}


	useEffect(() => {
		setupButton(nextButton, props.audioManager.nextAudioPath);
	}, [props.audioManager.nextAudioPath]);


	useEffect(() => {
		setupButton(prevButton, props.audioManager.prevAudioPath);
	}, [props.audioManager.prevAudioPath]);

	
	const nextPrevBtnClicked = (dir) => {
		console.log("next btn clicked");
		if (dir ==='next'){
			props.audioManager.reportAudioNav(props.audioManager.nextAudioPath, props.audioManager.nextAudioNum);
		} else {
			props.audioManager.reportAudioNav(props.audioManager.prevAudioPath, props.audioManager.prevAudioNum);
		}
	};
		
	
	const closeOnClick = useRef(false)

	useEffect(() => { 
		//cycleFnViewer();
		
		if (fnRef.current) {
			if (props.fnGloManager.cons === '') {
				['block', 'visible'  ].forEach(x => nukeClass(fnRef.current, x));
				['hidden', 'invisible'].forEach(x => addClass(fnRef.current, x));
				//setCloseOnClick(false);
				closeOnClick.current = false;
			} else {
                ['hidden', 'invisible'].forEach(x => nukeClass(fnRef.current, x));
				['block', 'visible' ].forEach(x => addClass(fnRef.current, x));
				//setCloseOnClick(true);
				setTimeout(() => closeOnClick.current = true, 250);
				
			}
		}
	// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [props.fnGloManager.cons]);

	useEffect(() => {
		console.log('adding event listener')
		if (typeof window !== "undefined") {
		window.addEventListener('click', closeCollapse)
		}

	}, [])
	

	// eslint-disable-next-line react-hooks/exhaustive-deps
	const closeCollapse = (e) => {
		if (!closeOnClick.current) return null;
		const wrapper = document.getElementById('fnglo-wrapper');	
		if (wrapper.classList.contains('visible') && !wrapper.contains(e.target)) {
			props.fnGloManager.closeFnViewer();
			closeOnClick.current = false;
		}
	};

	return (
		<footer class="fixed bottom-0 z-45 w-full bg-neutral border-t-2 border-black flex flex-col pb-2">
			
			<div id="fnglo-wrapper" 
				 ref={fnRef}
				 class="w-full hidden p-4 flex flex-col" 
				tabindex="0">
				<div class="overflow-y-auto max-h-36 w-full">
					<div class="flex flex-col w-full">
						<h2 class="text-xl text-center w-full mb-2" >{ props.fnGloManager.title }</h2>
						<div class="w-full align-center text-center" id="fnContents" >
							{props.fnGloManager.cons}
						</div>
					</div>
				</div>
				<a class="btn btn-ghost align-center"
							onclick={() => props.fnGloManager.closeFnViewer()}>{ configs.close }</a> 
			</div>
			<div class="w-full grid gird-cols-5">
				<button 
					style="visibility:hidden;"
					class="btn col-start-1 audio-button"
					onclick={() => nextPrevBtnClicked('prev')}
					ref={prevButton}>
					<i class="material-icons">navigate_before</i>
				</button>
				<div class="btn col-start-3" 
					style="visibility:hidden;"
					id="play-button"
					ref={playButton}
					onclick={() => props.audioManager.cycleAudio(false)}>
					<i class="material-icons" 
					id="play-btn-i"
					ref={audioI} />
				</div>
				<audio id="audio-elem" ref={audioElem} class="display:none;visibility:hidden;" />
				<button 
					class="btn col-start-5"
					style="visibility:hidden;"
					onclick={() => nextPrevBtnClicked('next')}
					ref={nextButton}>
					<i class="material-icons" disabled>navigate_next</i>
				</button>
			</div>
		</footer>
	);
}





