import '/css/input';
import { h, render } from 'preact';
import { PageHeader } from '/pageheader';
import { BookRenderer } from '/bookRenderer';
import { useEffect, useRef } from 'preact/hooks';
import { PageFooter } from '/pagefooter';
import { Router } from 'preact-router';
import { SearchPage } from '/searchpage';
import { NavigationManager } from '/navigationManager';
import { useStore } from '/store';
import { AudioManager } from '/audioManager';
import { FootnoteGloManager } from '/footnoteGloManager';
import { SnackBar } from '/snackBar';
import { TabControl } from './TabControl';




if (process.env.NODE_ENV==='development') {
	require('preact/debug');
}


function App(props){
	
	const toastRef = useRef(null);
	// const [toastMessage, setToastMessage] = useStore.toastMessage();
	const [firstLoad, ] = useStore.firstLoad();
	const [bookMenuShown] = useStore.bookMenuShown();
	
	const audioManager = new AudioManager({toastRef: toastRef, navManager: props.navManager});
	
	useEffect(() => {
		if (firstLoad) {
			props.navManager.setInitialBook();
		}
	}, [firstLoad, props.navManager])
	
	


	const fnGloManager = new FootnoteGloManager({toastRef, navManager: props.navManager});

	
	// useEffect(() => {
	// 	if (toastMessage !== '') {
	// 		if (toastRef.current){
	// 			toastRef.current.show(toastMessage);
	// 		}
	// 	}
	// }, [setToastMessage, toastMessage]);

	useEffect(() => {
		const bookMenu = document.getElementById('bookCptControl');
		const contents = document.getElementById('mainelem');
		if (bookMenuShown) {
			contents.style.visibility = 'hidden'
			contents.style.display = 'none';
			bookMenu.style.visibility = 'visible'
			bookMenu.style.display = 'block';
		} else {
			bookMenu.style.visibility = 'hidden'
			bookMenu.style.display = 'none';
			contents.style.visibility = 'visible'
			contents.style.display = 'block';
		}
	}, [bookMenuShown])

	
	return (
		<div class="container mx-auto">
			<header class="sticky top-0 z-50">
				<PageHeader 
					navManager={props.navManager} /> 
			</header>
			<div id="bookCptControl">
				<TabControl navManager={props.navManager} />
			</div>
			<BookRenderer 
				navManager={props.navManager}
				audioManager={audioManager}
				fnGloManager={fnGloManager} />
			<SnackBar ref={toastRef} />
			<PageFooter 
				navManager={props.navManager}
				audioManager={audioManager}
				fnGloManager={fnGloManager} />
			
		</div>
	);
}


function Main() {
	const navManager = new NavigationManager	;
	
	

	return (	
		<Router>
			<App default path="/" 
			    navManager={navManager} />
			<SearchPage path="/search" 
			    navManager={navManager} />
		</Router>
		
	);
}



if (typeof window !== "undefined") { 
	render(<Main />, document.body);
}

