import { h, Component, Fragment } from 'preact';
import { useRef, useEffect } from 'preact/hooks';
import { route } from 'preact-router';
import { configs } from '/configs';
import { useStore } from '/store';


class FontSizeDialog extends Component {
	
	changeSize = (modify) => {		
		const content = document.getElementById('content');
		const style = getComputedStyle(content);
		const newSize = modify(parseInt(style.fontSize, 10));
		content.style.fontSize = `${newSize}px`
  
		const newLineHeight = modify(parseInt(style.lineHeight, 10));        
		content.style.lineHeight =  `${newLineHeight}px`

		const fnWrapper = document.getElementById('fnglo-wrapper');
		const fnStyle = getComputedStyle(fnWrapper);
		const fnSize = modify(parseInt(fnStyle.fontSize, 10));
		const fnLineHeight = modify(parseInt(fnStyle.lineHeight, 10));
		fnWrapper.style.fontSize =  `${fnSize}px`;
		fnWrapper.style.lineHeight = `${fnLineHeight}px`;
	}
	
	upSize = () => {
		this.changeSize((x) => {return x + 2});
	};

	downSize = () => {
		this.changeSize((x) => {return  x - 2});
	}
	
		
	render() {
		return (
			<Fragment>
				<input type="checkbox" id="font-modal" class="modal-toggle" />
				<label for="font-modal" class="modal cursor-pointer">
					<label class="modal-box relative" for="">
						<div class="modal-actions flex flex-col">
							<h2 class="text-xl text-center w-full">{configs.change_font}</h2>
							<div class="btn-group place-self-center">
								<button class="btn btn-ghost" 
									id="decrease-font-size" 
									onclick={this.downSize}>-</button>
								<button class="btn btn-ghost" 
									id="increase-font-size" 
									onclick={this.upSize}>+</button>
							</div>
							<label for="font-modal" class="btn btn-ghost place-self-end" 
								id="close-font-size-dialog" 
								>{configs.close}</label>
						</div>
					</label>
				</label>
			</Fragment>
		)
	}
}


export  function HeaderMenu() {
	let deferredPrompt;
	let installLink = useRef(null);

	if (typeof window !== "undefined") {
		installLink.current = document.getElementById('installLink');

		window.addEventListener('appinstalled', () => {
			if (installLink.current) {
				installLink.current.classList.add('opacity-25');
				installLink.current.classList.add('pointer-events-none');
			}
		});

		window.addEventListener('beforeinstallprompt', (e) => {
			checkInstall('checking at beforeinstallprompt');
			e.preventDefault();
			deferredPrompt = e;
		});
	}
	
	const checkInstall = async (msg='') => {
		if (!installLink.current) {
			console.log("install link was null");
			return null;
		}

		const isStandalone = window.matchMedia('(display-mode: standalone)').matches;
		if (isStandalone) {
			console.log("Disabling install");
			installLink.current.classList.add('disabled-link');
		} else {
			installLink.current.classList.remove('disabled-link');
		}
		console.log(msg)
		
	};


	useEffect(() => {
		console.log("Checking PWA install status");
		installLink.current = document.getElementById('installLink');

		if (installLink.current) {
			checkInstall('checking at useEffect');
		} else {
			console.log("instalLink was null");
		}
	}, [])


	const installPwa = () => {
		console.log("Trying to install PWA");
		closeHeaderMenu();
		if (deferredPrompt){
			console.log("INSTALLING PWA for real this time");
			deferredPrompt.prompt()
		}
	};


	const closeHeaderMenu = () => { 
		// Close menu dialog 
		document.getElementById('closeMenuLink').click();
	};


	const openSearch = () => {
		closeHeaderMenu();
		route('/search');
	};


	return (
		<Fragment>
			<label for="my-modal" class="modal-button">
				<i class="material-icons text-base-100">more_vert</i>
			</label>
			<input type="checkbox" id="my-modal" class="modal-toggle" />
			<label for="my-modal" class="modal cursor-pointer">
				<label class="modal-box relative" for="">
					<ul class="p-2 bg-base-100">
						<li class="flex hover:bg-base-300 p-2 w-full" >
							<label for="font-modal" href="#" class="w-full" onclick={closeHeaderMenu}>{configs.change_font}</label>
						</li>
						<li class="flex hover:bg-base-300 p-2">
							<label for="my-modal" href="#" class="w-full" id="installLink" onclick={installPwa}>{configs.install}</label>
						</li>
						<li class="flex hover:bg-base-300 p-2" >
							<label for="my-model" href="/search" class="w-full" onclick={openSearch}>{configs.search}</label>
						</li>
					</ul>
					<div class="modal-action">
					<label for="my-modal" id="closeMenuLink" class="btn btn-ghost">{configs.close}</label>
					</div>
					
				</label>
			</label>
			<FontSizeDialog />
		</Fragment>			
	);
}


export function PageHeader() {	
	const [curBook, ] = useStore.curBook();
	const [curChapter, ] = useStore.curChapter();
	const [, setBookMenuShown] = useStore.bookMenuShown();


	const showTabSelect = () => {
		setBookMenuShown(true);
	}


	return (
		<div class="navbar bg-primary grid grid-cols-5 gap-2">
			
			<div class="col-start-1">
				<img src="icons/icon-36.png" id="nav-app-icon" style="min-height:36px; min-width:36px;" />
			</div>
			<div class="col-start-2 col-span-3 grid grid-cols-3  bg-base-100 p-2 ml-2 rounded" style="cursor: pointer;" onclick={showTabSelect}> 
				<div class="col-span-2 text-primary mr-6 truncate" style="cursor: pointer;">
					{curBook.name}
				</div>
				<div class="text-primary place-self-end" style="cursor: pointer;">
				{curChapter}
				</div>
			</div>

			<div class="col-start-5">
				<div class="flex-none">
					<HeaderMenu />
				</div>
			</div>
		</div>
	);
	
}

