import { useState } from 'preact/hooks';
import { gloData } from './glodata';
import { useStore } from './store';
import Markup  from 'preact-markup';
import { configs } from '/configs';

export function FootnoteGloManager(props) {
    const [fnGLoCons, setFnGLoCons] = useState('');
    const [fnGLoTitle, setFnGLoTitle] = useState('');
	const [bookCode, ] = useStore.bookCode();

    this.cons = fnGLoCons;
    this.title = fnGLoTitle;

    const Char = ({ style, children }) => {
        if (style === 'w') {
            return <span class={`glospan footnote ${style}`} onclick={() => this.showParatextContent('GLO', children)}>{ children }</span>
        } else if (style == 'k') {
            return '';
        }
        return <span class={style}>{ children }</span>
    };

	const Para =({ style, children }) => {
       
        return (
            <div class={style}>
                { children }
            </div>
        );
    }


	const removeVerses = (x) => {
		const parts = x.split(' ')
		parts.splice(parts.length -1, 1);
		return  parts.join(' ');
	};


    this.showParatextContent  = (ptype, info, children) => { 
		if (ptype === 'GLO') {
			if (!info) {
				info = children[0];
			}
			if (info in gloData) {
				const gloCons = gloData[info];
				setFnGLoCons(<Markup markup={gloCons} type="xml" trim={false} components={{ Char, Para }} />);
				setFnGLoTitle(info);
			}
		} else if (ptype === 'XR') {
			setFnGLoTitle('')
			const ref = info;
			const prettyName = children[0];
			if (ref.includes(bookCode)) {
				if (ref.includes('-')) {
					const [firstVerse, ] = ref.split('-', 2)
					const elem = document.getElementById(firstVerse);
					elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
				} else {
					const elem = document.getElementById(ref);
					elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
				}
			} else {
				console.log('ref in other book');
				const inApp = props.navManager.books.some(x => { 
					return ref.includes(x.code) 
				});
				if (inApp) {
					props.navManager.navFromRef(ref);
				} else if (props.toastRef.current) {
					console.log('not in App');
					props.toastRef.current.show(configs.notinappyet.replace('NAME', removeVerses(prettyName)), 300);
				}
			}
		} else {	
			setFnGLoTitle('');
			setFnGLoCons(children);
		}
	};


    this.setFnTitle = setFnGLoTitle;

    this.closeFnViewer = () => {
		setFnGLoCons('');
		setFnGLoTitle('');
	};

}