
import createStore from "teaful";
import { bookData } from './bookData';
import { chapterData } from './chapterdata';


const initialBook = bookData[1]
const initialChapters = chapterData[initialBook.code]


let initialStore = {
    chapters: initialChapters,
    books: bookData,
    bookCode: '',
    installVisible: 'none',
    toastMessage: '',
    hasInternet: true,
    bookMenuShown: false,
    curName: '',
    curBook: initialBook,
    curChapter: initialChapters[0].number,
    xmlData: null,
    firstLoad: true,
    navTarget: '',
    navTargetSearch: '',
    showToast: true
};


export const { useStore } = createStore(initialStore); 

