import { Fragment } from 'preact';
import { useStore } from '/store';
import { configs } from "/configs";

export function TabControl(props) {
	const [, setBookMenuShown] = useStore.bookMenuShown();


	function changeActiveTab(event, tabID) {
		let element = event.target;
		while (element.nodeName !== "A") {
			element = element.parentNode;
		}
		const ulElement = element.parentNode.parentNode;
		const aElements = ulElement.querySelectorAll("li > a");
		const tabContents = document.getElementById("tabs-id").querySelectorAll(".tab-content > div");
		for (let i = 0; i < aElements.length; i++) {
			aElements[i].classList.remove("text-white");
			aElements[i].classList.remove("bg-primary");
			aElements[i].classList.add("text-primary");
			aElements[i].classList.add("bg-white");
			tabContents[i].classList.add("hidden");
			tabContents[i].classList.remove("block");
		}
		element.classList.remove("text-primary");
		element.classList.remove("bg-white");
		element.classList.add("text-white");
		element.classList.add("bg-primary");
		document.getElementById(tabID).classList.remove("hidden");
		document.getElementById(tabID).classList.add("block");
	}


	const setBook = (book) => {
		document.getElementById('tab-cpt').click();
		props.navManager.updateBook(book);
	};


	const doNav = (item) => {
		setBookMenuShown(false);
		props.navManager.requestCptNav(item.cid, item.number);
	};

	return (
		<Fragment>
			<div class="flex flex-wrap" id="tabs-id">
				<div class="w-full">
					<ul class="flex mb-0 list-none flex-wrap pt-3 pb-4 flex-row">
						<li class="-mb-px mr-2 last:mr-0 flex-auto text-center">
							<a class="text-xs font-bold uppercase px-5 py-3 shadow-lg rounded block leading-normal text-white bg-primary"
								style="cursor: pointer;"
								onclick={(event) => changeActiveTab(event, 'tab-one')}>
								<i class="fas fa-space-shuttle text-base mr-1" /> {configs.book}
							</a>
						</li>
						<li class="-mb-px mr-2 last:mr-0 flex-auto text-center">
							<a class="text-xs font-bold uppercase px-5 py-3 shadow-lg rounded block leading-normal text-primary bg-white"
								style="cursor: pointer;"
								id="tab-cpt"
								onclick={(event) => changeActiveTab(event, 'tab-two')}>
								<i class="fas fa-cog text-base mr-1" />{configs.chapter}
							</a>
						</li>

					</ul>
					<div class="relative flex flex-col min-w-0 break-words bg-white w-full mb-6 shadow-lg rounded">
						<div class="px-4 py-5 flex-auto">
							<div class="tab-content tab-space">
								<div class="block" id="tab-one">
									<div class="flex flex-wrap overflow-y-auto max-h-64">
										{props.navManager.books.map(item => <div class="w-full hover:bg-base-300 p-2" key={item.name}
											style="cursor:pointer;"
											onclick={() => setBook(item)}>{item.name}</div>)}
									</div>
								</div>
								<div class="hidden" id="tab-two">
									<div class="flex flex-wrap overflow-y-auto max-h-64">
										{props.navManager.chapters.map(item => <div key={item.cid}
											class="hover:bg-base-300 p-2 m-2 text-lg"
											onclick={() => doNav(item)}>{item.number}</div>)}
									</div>
								</div>

							</div>
						</div>
					</div>
				</div>
			</div>
		</Fragment>

	);
}
