import { audioData } from './audiodata';
import { useState, useEffect } from 'preact/hooks';
import { useStore } from './store';
import { configs } from './configs';


export function AudioManager(props) {
    const [audioPath, setAudioPath] = useState('');
	const [nextAudio, setNextAudio] = useState('');
	const [prevAudio, setPrevAudio] = useState('');
	const [nextAudioNum, setNextAudioNum] = useState('');
	const [prevAudioNum, setPrevAudioNum] = useState('');
	const [audioElem, setAudioElem] = useState(null);
	const [audioI, setAudioI] = useState(null);
	const [playButton, setPlayButton] = useState(null);
    const [ bookCode, ] = useStore.bookCode();
	const [showToast, setShowToast] = useState(true);
	const [audioElemsInjected, setAudioElemsInjected] = useState(false);


    this.audioPath = audioPath;
	this.setAudioPath = setAudioPath;
    this.nextAudioPath = nextAudio;
    this.prevAudioPath = prevAudio;
    this.nextAudioNum = nextAudioNum;
    this.prevAudioNum = prevAudioNum;
	

	useEffect(() => {
		setAudioPath('');
		setNextAudio('');
		setNextAudioNum('');
		setPrevAudio('');
		setPrevAudioNum('');
	}, [bookCode])


    const addOne = (x) => {
        return (parseInt(x, 10) + 1).toString();
    };


    const subtractOne = (x) => {
        return (parseInt(x, 10) - 1).toString();
    }


	this.injectAudioElems = (elemRef, iRef, playRef ) => {
		if (elemRef.current && iRef.current && playRef.current) {
			setAudioElem(elemRef.current);
			setAudioI(iRef.current);
			setPlayButton(playRef.current)
			setAudioElemsInjected(true);
		}
	}


    this.reportAudioNav = (newPath, newNum) => {
		console.log("Audio nav: " + newNum);
		props.navManager.requestCptNavOnNum(newNum);
		this.updateAudioData(newPath, newNum, true);
	};


	this.setupAudio = (audioUrl) => {
		if (!audioUrl) {
			audioUrl = audioPath;
		}
		if (audioElemsInjected) {
			if (audioUrl === '') {
				playButton.style.visibility = 'hidden';
			} else {
				playButton.style.visibility = 'visible';
				audioElem.src = configs.audioUrl + audioUrl;
			}
		}
	}

	// was called when audio URL was updated
	this.handleNewAudioUrl = (url=null, calledFromSideButton=false) => {
		console.log("handilng new audio url")
		if (audioElemsInjected) {		
			if (!audioElem.paused) {
				stopAudio();
			}
			this.setupAudio(url);
			this.cycleAudio(calledFromSideButton);
		} else {
			this.setupAudio(url);
		}
	}



	this.updateAudioData = (fname, number, calledFromSideButton=false) => {
		console.log("updating audio Data")
		let next = '';
		let nextNum = addOne(number);
		let prev = '';
		let prevNum = subtractOne(number);
		console.log(number + " " + prevNum + ' ' + nextNum);

		if (nextNum in audioData[bookCode]){
			next = audioData[bookCode][nextNum];
		} else {
			nextNum = '';
		}
		if (prevNum in audioData[bookCode]){
			prev = audioData[bookCode][prevNum];
		} else {
			prevNum = '';
		}
		setNextAudio(next);
		setNextAudioNum(nextNum);
		setPrevAudio(prev);
		setPrevAudioNum(prevNum);
		// next line triggers this.handleNewAudioUrl
		//setAudioPath(fname); 
		this.handleNewAudioUrl(fname, calledFromSideButton);
		
	};

	const stopAudio = () => {
		audioElem.pause();
		audioI.innerHTML = 'play_arrow';
	}

	const playAudio = () => {
		audioElem.play();
		audioI.innerHTML = 'pause';  
	}

	useEffect(() => {
		if (!showToast) {
			setTimeout(() => setShowToast(true), configs.internetToastTimeout)
		}
	}, [setShowToast, showToast])
  
	this.cycleAudio = (calledFromSideButton=false) => {
		if (audioElemsInjected) {

			if (audioElem.paused){
				if (navigator.onLine) {
					playAudio();       		
				} else {
					stopAudio();
					if (showToast) {
						if (!calledFromSideButton) {
							props.toastRef.current.show(configs.needInternetToListen);
							setShowToast(false);
						}
					} 
				}		
			} else {
				stopAudio();
			}
			
		}
	};

}